public CreatureCommand Act(int x, int y)
{
    if (FindPlayer()) // Предполагаем, что метод FindPlayer возвращает true, если игрок найден
    {
        // Упрощаем вычисление направления
        int xTo = Math.Sign(Player.xPos - x);
        int yTo = Math.Sign(Player.yPos - y);

        // Проверяем, необходимо ли двигаться по диагонали (приоритет направления)
        if (xTo != 0 && yTo != 0)
        {
            if (Player.yPos == y) // Если игрок находится на той же горизонтальной линии
                yTo = 0; // Сбрасываем вертикальное направление
            else
                xTo = 0; // Иначе сбрасываем горизонтальное направление
        }

        // Если следующий шаг выходит за пределы карты, бросим вызов с нулевыми изменениями
        if (!IsWithinMapBounds(x + xTo, y + yTo))
            return new CreatureCommand() { DeltaX = 0, DeltaY = 0 };

        // Если следующий шаг ведет на другое существо, бросим вызов с нулевыми изменениями
        if (IsOtherCreature(x + xTo, y + yTo))
            return new CreatureCommand() { DeltaX = 0, DeltaY = 0 };

        // Передаем команду для движения
        return new CreatureCommand() { DeltaX = xTo, DeltaY = yTo };
    }
    // Если игрок не найден, бросим вызов с нулевыми изменениями
    return new CreatureCommand() { DeltaX = 0, DeltaY = 0 };
}

private bool IsWithinMapBounds(int x, int y)
{
    return x >= 0 && x < Game.MapWidth && y >= 0 && y < Game.MapHeight;
}

private bool IsOtherCreature(int x, int y)
{
    var mapObject = Game.Map[x, y];
    return mapObject != null && 
           (mapObject.ToString() == "Digger.Terrain" || 
            mapObject.ToString() == "Digger.Sack" || 
            mapObject.ToString() == "Digger.Monster");
}
