public CreatureCommand Act(int x, int y)
{
    // Инициализируем направления передвижения
    int xTo = 0;
    int yTo = 0;

    // Пытаемся найти игрока
    if (FindPlayer())
    {
        // Если игрок по вертикальной оси находится с нами на одной линии
        if (Player.xPos == x)
        {
            // Определяем, нужно ли двигаться вверх или вниз
            if (Player.yPos < y) yTo = -1;    // Вверх
            else if (Player.yPos > y) yTo = 1; // Вниз
        }
        // Если игрок по горизонтальной оси находится с нами на одной линии
        else if (Player.yPos == y)
        {
            // Определяем, нужно ли двигаться влево или вправо
            if (Player.xPos < x) xTo = -1;    // Влево
            else if (Player.xPos > x) xTo = 1; // Вправо
        }
        // Если игрок находится не на одной с нами линии по обеим осям
        else
        {
            // Выбираем направление по горизонтальной оси
            if (Player.xPos < x) xTo = -1;    // Влево
            else if (Player.xPos > x) xTo = 1; // Вправо
        }
    }
    else
    {
        // Если игрок не найден, остаёмся на месте
        return new CreatureCommand() { DeltaX = 0, DeltaY = 0 };
    }

    // Проверяем, находится ли следующая посчитанная позиция в пределах карты
    // (проверка не выйдем ли мы за границы массива и карты)
    if (x + xTo >= 0 && x + xTo < Game.MapWidth && y + yTo >= 0 && y + yTo < Game.MapHeight)
    {
        // Получаем объект карты по следующей позиции
        var map = Game.Map[x + xTo, y + yTo];

        // Если позиция не пуста и у нас есть там другое существо (Земля, Мешок или Монстр)
        if (map != null && (map.ToString() == "Digger.Terrain" || map.ToString() == "Digger.Sack" || map.ToString() == "Digger.Monster"))
        {
            // Остаёмся на месте
            return new CreatureCommand() { DeltaX = 0, DeltaY = 0 };
        }
        else
        {
            // Двигаемся в расчитанную позицию
            return new CreatureCommand() { DeltaX = xTo, DeltaY = yTo };
        }
    }
    else
    {
        // Если следующая позиция вне карты, остаёмся на месте
        return new CreatureCommand() { DeltaX = 0, DeltaY = 0 };
    }
}
