        }
        // Если игрок находится на той же горизонтальной линии
        else if (Player.yPos == y)
        {
            // Определяем, двигаться влево или вправо
            if (Player.xPos < x) xTo = -1; // Игрок левее нас, движемся влево
            else if (Player.xPos > x) xTo = 1; // Игрок правее нас, движемся вправо
        }
        // Если игрок не находится ни на одной из наших линий
        else
        {
            // Определяем горизонтальное направление движения
            if (Player.xPos < x) xTo = -1; // Игрок левее нас, движемся влево
